INSERT INTO "scam_addresses" ("address","chain","case_slug","role","label","entity","balance_note","first_seen","last_seen","sources","confidence","updated_at","entity_id","cluster_id") VALUES ('0xaaaebe6fe48e54f431b0c390cfaf0b017d09d42d','ethereum','celsius-2022','token-contract','Celsius (CEL) ERC-20 token contract','Celsius Network','CelsiusToken contract; 4 decimals; ~35.7M max supply. The token whose price was manipulated via customer-funded buybacks.',NULL,NULL,'["https://etherscan.io/token/0xaaaebe6fe48e54f431b0c390cfaf0b017d09d42d"]','confirmed','2026-07-08 21:16:29','celsius-network','celsius-onchain');
INSERT INTO "scam_addresses" ("address","chain","case_slug","role","label","entity","balance_note","first_seen","last_seen","sources","confidence","updated_at","entity_id","cluster_id") VALUES ('0x81b5ce15aa64e1dcefc18f810de7d18115230586','ethereum','celsius-2022','treasury','Celsius Network: CEL Treasury Reserve','Celsius Network','Etherscan public name tag ''Celsius Network: CEL Treasury Reserve'' (labels: Celsius Network, Token Contract, Treasury). Held CEL used in the token-support program.',NULL,NULL,'["https://etherscan.io/address/0x81b5ce15aa64e1dcefc18f810de7d18115230586"]','confirmed','2026-07-08 21:16:33','celsius-network','celsius-onchain');
