INSERT INTO "scam_addresses" ("address","chain","case_slug","role","label","entity","balance_note","first_seen","last_seen","sources","confidence","updated_at","entity_id","cluster_id") VALUES ('0xb26314635252b4ee8b454423e5299a092dea8a4a','ethereum','celsius-2022','operational-wallet','Celsius Network wallet (''Celsius 12'')','Celsius Network','Etherscan public name tag observed as ''Celsius 12'' (labels: Celsius Network, Loans). Some search indexes list it as ''Celsius Network: Wallet 4'' — label ambiguity noted; entity attribution to Celsius Network confirmed on-chain.',NULL,NULL,'["https://etherscan.io/address/0xb26314635252b4ee8b454423e5299a092dea8a4a"]','confirmed','2026-07-08 21:16:44','celsius-network','celsius-onchain');
