INSERT INTO "scam_actors" ("slug","case_slug","real_name","aliases","role","nationality","status","links","summary","sources","updated_at") VALUES ('alex-mashinsky','celsius-2022','Alexander Mashinsky','Alex Mashinsky','Founder & CEO of Celsius Network; architect of the fraud and CEL manipulation scheme','Ukrainian-American (Israeli-raised)','Convicted — sentenced 2025-05-08 to 12 years in federal prison; $48M forfeiture','[{"label":"DOJ sentencing press release","url":"https://www.justice.gov/usao-sdny/pr/founder-celsius-sentenced-12-years-fraud-and-market-manipulation"},{"label":"DOJ guilty plea release","url":"https://www.justice.gov/usao-sdny/pr/celsius-founder-and-former-ceo-alexander-mashinsky-pleads-guilty-multi-billion-dollar"},{"label":"SEC press release 2023-133","url":"https://www.sec.gov/newsroom/press-releases/2023-133"}]','Founder and former CEO of Celsius Network. Led the platform''s public messaging (''Unbank Yourself'', weekly AMAs) and made false statements about profitability, liquidity, and safety of customer assets. Directed and profited from the CEL token manipulation scheme, personally reaping ~$42M (per 2023 indictment) / ~$48M (per sentencing) from CEL sales at manipulated prices while publicly claiming he was ''HODLing.'' Pleaded guilty 2024-12-03 to commodities fraud and a CEL-manipulation scheme; sentenced to 12 years by Judge Koeltl on 2025-05-08. Separately hit with SEC, CFTC (permanent trading ban), and FTC ($10M + lifetime crypto/financial ban) actions.','["https://www.justice.gov/usao-sdny/pr/founder-celsius-sentenced-12-years-fraud-and-market-manipulation","https://www.justice.gov/d9/2023-07/u.s._v._mashinsky_and_cohen-pavon_indictment.pdf","https://www.cftc.gov/PressRoom/PressReleases/8749-23"]','2026-07-08 21:16:00');
INSERT INTO "scam_actors" ("slug","case_slug","real_name","aliases","role","nationality","status","links","summary","sources","updated_at") VALUES ('roni-cohen-pavon','celsius-2022','Roni Cohen-Pavon','Roni Cohen Pavon','Chief Revenue Officer of Celsius; co-conspirator in CEL token manipulation','Israeli','Convicted — pleaded guilty 2023-09-13; cooperated; sentenced to time served + supervised release, ~$1M restitution + $40K fine','[{"label":"DOJ charging press release","url":"https://www.justice.gov/usao-sdny/pr/celsius-founder-and-former-chief-revenue-officer-charged-connection-multibillion"},{"label":"Cointelegraph guilty plea","url":"https://cointelegraph.com/news/former-celsius-exec-pleads-guilty-criminal-charges"}]','Celsius''s former Chief Revenue Officer and co-defendant with Mashinsky. Participated directly in manipulating the CEL token price, personally reaping at least $3.6M from CEL sales at inflated prices. Privately warned Mashinsky the token''s value ''was fake and was based on us spending millions.'' Pleaded guilty 2023-09-13 to conspiracy to commit price manipulation, securities fraud, manipulation of security prices, and wire fraud; provided substantial cooperation that helped prompt Mashinsky''s guilty plea. Sentenced to time served plus supervised release.','["https://www.justice.gov/usao-sdny/pr/celsius-founder-and-former-chief-revenue-officer-charged-connection-multibillion","https://decrypt.co/197292/celsius-exec-pleads-guilty-agrees-to-cooperate-in-case-against-ceo"]','2026-07-08 21:16:06');
INSERT INTO "scam_actors" ("slug","case_slug","real_name","aliases","role","nationality","status","links","summary","sources","updated_at") VALUES ('shlomi-daniel-leon','celsius-2022','Shlomi Daniel Leon','Daniel Leon','Co-founder & Chief Strategy Officer / COO of Celsius Network','Israeli','Charged (civil) by FTC 2023-07-13; not settled — FTC case ongoing; no criminal charges','[{"label":"FTC press release","url":"https://www.ftc.gov/news-events/news/press-releases/2023/07/ftc-reaches-settlement-crypto-platform-celsius-network-charges-former-executives-duping-consumers"},{"label":"FTC complaint (PDF)","url":"https://www.ftc.gov/system/files/ftc_gov/pdf/2223137celsiusnetworkcomplaint.pdf"}]','Co-founder of Celsius and Chief Strategy Officer (also COO of Celsius Network LLC, President of Celsius Mining LLC). Named by the FTC as one of three executives who duped consumers into depositing crypto by falsely promising safety and availability. Per the FTC, Leon, Goldstein, and Mashinsky protected themselves by withdrawing significant sums of cryptocurrency two months before the bankruptcy filing while telling customers not to withdraw. Has not settled with the FTC; the civil case against him remains in litigation. Not criminally charged.','["https://www.ftc.gov/news-events/news/press-releases/2023/07/ftc-reaches-settlement-crypto-platform-celsius-network-charges-former-executives-duping-consumers"]','2026-07-08 21:16:16');
INSERT INTO "scam_actors" ("slug","case_slug","real_name","aliases","role","nationality","status","links","summary","sources","updated_at") VALUES ('hanoch-goldstein','celsius-2022','Hanoch Goldstein','Nuke Goldstein; Hanoch "Nuke" Goldstein','Co-founder & Chief Technology Officer of Celsius Network','Israeli','Charged (civil) by FTC 2023-07-13; not settled — FTC case ongoing; no criminal charges','[{"label":"FTC press release","url":"https://www.ftc.gov/news-events/news/press-releases/2023/07/ftc-reaches-settlement-crypto-platform-celsius-network-charges-former-executives-duping-consumers"},{"label":"FTC complaint (PDF)","url":"https://www.ftc.gov/system/files/ftc_gov/pdf/2223137celsiusnetworkcomplaint.pdf"}]','Co-founder of Celsius and Chief Technology Officer (until March 2022; also President of Labs). Sat on the Executive and Risk Committees and appeared in Celsius marketing videos. Named by the FTC as one of three executives who deceived consumers about the safety of their deposits and who withdrew significant crypto from Celsius roughly two months before bankruptcy while discouraging customer withdrawals. Has not settled with the FTC; case ongoing. Not criminally charged.','["https://www.ftc.gov/news-events/news/press-releases/2023/07/ftc-reaches-settlement-crypto-platform-celsius-network-charges-former-executives-duping-consumers"]','2026-07-08 21:16:21');
